SELECT  AP_TICKET_CNT
FROM t_applicaiton_manager

WHERE	AP_KEYNO	=	#{AP_KEYNO}

	SELECT * 




 		ORDER BY	KEYNO ${sortDirect}


 		ORDER BY	AP_NAME ${sortDirect}


 		ORDER BY	TYPENAME ${sortDirect}


 		ORDER BY	CAST(REPLACE(REPLACE(PRICE, ',', ''), '원', '') AS UNSIGNED) ${sortDirect}


 		ORDER BY	PM_NAME ${sortDirect}


 		ORDER BY	UI_NAME ${sortDirect}


 		ORDER BY	AP_REGDT ${sortDirect}


 		ORDER BY	AP_USE_NM ${sortDirect}


 		ORDER BY 	AP_KEYNO DESC



	 	LIMIT  	#{recordCountPerPage} OFFSET #{firstIndex}

SELECT CASE WHEN AP.AP_USE = 'N' THEN '사용안함' WHEN AP.AP_USE = 'Y' THEN '사용함' END AS AP_USE_NM , STR_TO_DATE(NOW(),'%Y-%m-%d') NOW_DATE , CASE WHEN AP.AP_DEADLINE = 'N' THEN '진행중' WHEN AP.AP_DEADLINE = 'Y' THEN '마감' END AS DEADLINE , AP.* , P.PM_NAME , U.UI_NAME , GROUP_CONCAT(AD_KEYNO) AD_KEYNO , CS.SC_CODENM AS TYPENAME FROM t_applicaiton_manager AP LEFT JOIN t_place_manager P ON AP.AP_PLACE = P.PM_KEYNO LEFT JOIN u_userinfo U ON AP.AP_REGNM = U.UI_KEYNO LEFT JOIN t_applicaiton_discount_select ADS ON AP.AP_KEYNO = ADS.AP_KEYNO LEFT JOIN s_common_code_sub CS ON AP.AP_TYPE = CS.SC_KEYNO WHERE AP_USE != 'D'
AND AP.AP_KEYNO = #{AP_KEYNO}
GROUP BY AP.AP_KEYNO ORDER BY AP.AP_KEYNO DESC

	SELECT * 



 		ORDER BY	COUNT ${sortDirect}


 		ORDER BY	DIVISION ${sortDirect}


 		ORDER BY	AP_NAME ${sortDirect}


 		ORDER BY	UI_NAME ${sortDirect}


 		ORDER BY	SEQ ${sortDirect}


 		ORDER BY	PRICE ${sortDirect}


 		ORDER BY	APP_REGDT ${sortDirect}


 		ORDER BY	STATUS ${sortDirect}


 		ORDER BY 	COUNT DESC



	 	LIMIT  	#{recordCountPerPage} OFFSET #{firstIndex}

