mapper.update:
UPDATE t_application_discount 
SET		AD_NAME				=	#{AD_NAME}
	  , AD_TYPE				=	#{AD_TYPE}
	  , AD_MONEY			=	#{AD_MONEY}
	  , AD_COMENT			=	#{AD_COMENT}
	  , AD_DEFAULT_YN		=	#{AD_DEFAULT_YN}
	  , AD_USE				=	#{AD_USE}
WHERE	AD_KEYNO			=	#{AD_KEYNO}

UPDATE t_application_discount
SET		AD_USE		=	'D'
WHERE	AD_KEYNO	=	#{AD_KEYNO}

mapper.sql:
FROM ( SELECT @rownum:=@rownum+1 as COUNT , A.* FROM( SELECT IF(AD.AD_TYPE = 'A', CONCAT(AD.AD_MONEY,'%'), CONCAT(AD.AD_MONEY,'원')) MONEY , AD.AD_NAME , AD.AD_COMENT , CASE AD_USE WHEN 'Y' THEN 'O' WHEN 'N' THEN 'X' END AD_USE , CASE AD_DEFAULT_YN WHEN 'Y' THEN 'O' WHEN 'N' THEN 'X' END AD_DEFAULT_YN , CAST(RIGHT(AD_KEYNO,10) AS UNSIGNED) AD_KEYNO FROM t_application_discount AD WHERE AD_USE != 'D' AND AD_TYPE != 'C' ORDER BY AD_KEYNO ) A WHERE (@ROWNUM:=0)=0 ) BB WHERE 1=1
AND COUNT LIKE CONCAT( '%',#{item.searchKeyword},'%')
AND AD_NAME LIKE CONCAT( '%',#{item.searchKeyword},'%')
AND AD_USE = #{item.searchKeyword}
AND MONEY LIKE CONCAT( '%',#{item.searchKeyword},'%')
AND AD_COMENT = #{item.searchKeyword}
AND AD_DEFAULT_YN = #{item.searchKeyword}
AND ( COUNT LIKE CONCAT( '%',#{item.searchKeyword},'%') OR AD_NAME LIKE CONCAT( '%',#{item.searchKeyword},'%') OR AD_USE = #{item.searchKeyword} OR MONEY LIKE CONCAT( '%',#{item.searchKeyword},'%') OR AD_COMENT LIKE CONCAT( '%',#{item.searchKeyword},'%') OR AD_DEFAULT_YN = #{item.searchKeyword} )

mapper.select:
	SELECT * 



 		ORDER BY	COUNT ${sortDirect}


 		ORDER BY	AD_NAME ${sortDirect}


 		ORDER BY	AD_USE ${sortDirect}


 		ORDER BY	CAST(REPLACE(REPLACE(MONEY, '원',''),'%','') AS UNSIGNED)	${sortDirect}


 		ORDER BY	AD_COMENT 	${sortDirect}


 		ORDER BY	AD_DEFAULT_YN ${sortDirect}


 		ORDER BY 	COUNT DESC



	 	LIMIT  	#{recordCountPerPage} OFFSET #{firstIndex}

